    def evaluate(self, s: str) -> float:

        def precedence(op):
            if op in ['*', '/']:
                return 2
            if op in ['+', '-']:
                return 1
            return 0

        def applyOps(nums, ops):
            result = nums[0]
            i = 0
            while i < len(ops):
                if ops[i] == '+' or ops[i] == '-':
                    result = nums[i] + ops[i] * nums[i+1]
                    nums.pop(i)
                    nums.pop(i)
                    nums.insert(i, result)
                elif ops[i] == '*':
                    result = nums[i] * nums[i+1]
                    nums.pop(i)
                    nums.pop(i)
                    nums.insert(i, result)
                elif ops[i] == '/':
                    result = nums[i] / nums[i+1]
                    nums.pop(i)
                    nums.pop(i)
                    nums.insert(i, result)
                i+=1
            return nums[0]

        nums = []
        ops = []
        i = 0
        while i < len(s):
            if s[i] >= '0' and s[i] <= '9':
                num = ''
                while i < len(s) and s[i] >= '0' and s[i] <= '9':
                    num += s[i]
                    i += 1
                nums.append(int(num))
            elif s[i] in ['+', '-', '*', '/']:
                op = s[i]
                i += 1
                while i < len(s) and s[i] >= '0' and s[i] <= '9':
                    i += 1
                ops.append(op)
            else:
